"use client";

/* ════════════════════════════════════════════════════════════════════════
   Bridge shell — the route layout for /bridge/[dept]/[surface].

   Full-page workbench (parchment), fixed over the app rail. Renders the
   chrome — gutter + chat panel + topbar (pipe-mark, back, dept-tabs, close)
   + per-dept subnav — and slots the active surface page as {children}.

   Ported from the old BridgeOverlay shell; now route-driven (Links + router)
   so every surface is a unique, deep-linkable, code-split URL.
   ════════════════════════════════════════════════════════════════════════ */

import Link from "next/link";
import { useParams } from "next/navigation";
import { useState } from "react";
import { useBridge, type BridgeDept } from "@/features/bridge/hooks/use-bridge";
import {
  DEPT_TABS,
  DEPT_LABEL,
  SUBNAV_FOR,
  GROWTH_CHANNELS,
} from "@/features/bridge/api/bridge-subnav";
import "@/features/bridge/components/bridge.css";

export default function BridgeLayout({ children }: { children: React.ReactNode }) {
  const params = useParams();
  const { dept, closeBridge, setDept } = useBridge();
  const activeSurface = (params?.surface as string | undefined) ?? null;

  const [chatOpen, setChatOpen] = useState(false);
  // Growth drill-down (UI only — Growth surfaces aren't built yet)
  const [growthChannel, setGrowthChannel] = useState<string | null>(null);
  const [growthItem, setGrowthItem] = useState<string | null>(null);

  const switchDept = (d: BridgeDept) => {
    setGrowthChannel(null);
    setGrowthItem(null);
    setDept(d);
  };

  return (
    <aside className="bridge-overlay as-page" data-dept={dept} aria-label="The Bridge">
      {/* ── Vertical gutter with chat toggle ── */}
      <div className="bridge-gutter">
        <div className="bridge-gutter-text">MAGELLAN</div>
        <button
          className="bridge-gutter-handle"
          onClick={() => setChatOpen((v) => !v)}
          aria-label={chatOpen ? "Collapse Magellan chat" : "Open Magellan chat"}
          type="button"
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round">
            <polyline points="9 18 15 12 9 6" />
          </svg>
        </button>
      </div>

      {/* ── Chat panel ── */}
      <aside className={`bridge-chat-panel${chatOpen ? " open" : ""}`}>
        <div className="bridge-chat-inner">
          <header className="bridge-chat-head">
            <div className="bridge-chat-head-left">
              <div className="bridge-chat-m">M</div>
              <div className="bridge-chat-head-title">
                <div className="bridge-chat-head-name">Magellan</div>
                <div className="bridge-chat-head-ctx">{DEPT_LABEL[dept]}</div>
              </div>
            </div>
            <div className="bridge-chat-head-actions">
              <button className="bridge-chat-icon-btn" title="New thread" type="button">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
                  <line x1="12" y1="5" x2="12" y2="19" />
                  <line x1="5" y1="12" x2="19" y2="12" />
                </svg>
              </button>
              <button className="bridge-chat-icon-btn" title="Collapse" type="button" onClick={() => setChatOpen(false)}>
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
                  <polyline points="15 18 9 12 15 6" />
                </svg>
              </button>
            </div>
          </header>

          <div className="bridge-chat-body">
            <div className="bridge-msg">
              <div className="bridge-msg-author-line">
                <span className="name">
                  Magellan
                  <svg viewBox="0 0 22 16">
                    <path d="M2 14 L2 2 L7 11 L11 6 L15 11 L20 2 L20 14" fill="none" stroke="currentColor" strokeWidth="1.5" />
                  </svg>
                </span>
                <span className="sep" />
                <span className="time">10:24</span>
              </div>
              <div className="bridge-msg-body">
                I&rsquo;m scoped to <b>{DEPT_LABEL[dept]}</b>. Ask me to draft, classify, reconcile, or walk through any action on this bench.
              </div>
            </div>
          </div>

          <div className="bridge-chat-composer">
            <div className="bridge-composer-wrap">
              <input className="bridge-composer-input" placeholder="Ask Magellan…" type="text" />
              <div className="bridge-composer-row">
                <button className="bridge-composer-btn" title="Attach" type="button">
                  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
                    <path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48" />
                  </svg>
                </button>
                <span className="bridge-composer-spacer" />
                <button className="bridge-composer-send" title="Send" type="button">
                  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
                    <line x1="12" y1="19" x2="12" y2="5" />
                    <polyline points="5 12 12 5 19 12" />
                  </svg>
                </button>
              </div>
            </div>
            <div className="bridge-composer-foot">
              <span className="scoped">Scoped to {DEPT_LABEL[dept]}</span>
            </div>
          </div>
        </div>
      </aside>

      {/* ── Bridge main (parchment workbench) ── */}
      <main className="bridge-main">
        <header className="bridge-topbar">
          <div className="bridge-pipe">
            <span className="bridge-pipe-mark" />
            <span className="bridge-pipe-text">The Bridge</span>
          </div>

          <button className="bridge-back" onClick={closeBridge} type="button">
            <span className="bridge-back-arrow">←</span>
            <span>Back to {DEPT_LABEL[dept]} Overview</span>
          </button>

          <nav className="bridge-dept-tabs">
            {DEPT_TABS.map((t) => (
              <button
                key={t.id}
                className={`bridge-dept-tab${t.id === dept ? " active" : ""}`}
                type="button"
                onClick={() => switchDept(t.id)}
              >
                <span className={`bridge-dept-dot ${t.id}`} />
                <span>{t.label}</span>
              </button>
            ))}
          </nav>

          <button className="bridge-close" onClick={closeBridge} type="button" aria-label="Close Bridge">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round">
              <line x1="6" y1="6" x2="18" y2="18" />
              <line x1="18" y1="6" x2="6" y2="18" />
            </svg>
          </button>
        </header>

        {/* Subnav — per-dept */}
        <nav className="bridge-subnav">
          {dept === "growth" ? (
            growthChannel === null ? (
              <>
                <span className="bridge-subnav-section">Growth</span>
                <span className="bridge-subnav-divider" />
                {GROWTH_CHANNELS.map((c) => (
                  <button
                    key={c.id}
                    className="bridge-subnav-item"
                    type="button"
                    onClick={() => {
                      setGrowthChannel(c.id);
                      setGrowthItem(c.items[0] ?? null);
                    }}
                  >
                    {c.label}
                  </button>
                ))}
              </>
            ) : (
              <>
                <span className="bridge-subnav-section">Growth</span>
                <span className="bridge-subnav-divider" />
                <button
                  className="bridge-subnav-item bridge-subnav-back"
                  type="button"
                  onClick={() => {
                    setGrowthChannel(null);
                    setGrowthItem(null);
                  }}
                  aria-label="Back to Growth channels"
                >
                  <span className="back-arrow">‹</span>
                  {GROWTH_CHANNELS.find((c) => c.id === growthChannel)?.label}
                </button>
                {GROWTH_CHANNELS.find((c) => c.id === growthChannel)?.items.map((it) => (
                  <button
                    key={it}
                    className={`bridge-subnav-item${growthItem === it ? " active" : ""}`}
                    type="button"
                    onClick={() => setGrowthItem(it)}
                  >
                    {it}
                  </button>
                ))}
              </>
            )
          ) : (
            SUBNAV_FOR[dept].map((s, i) => {
              if (s.kind === "divider") return <span key={i} className="bridge-subnav-divider" />;
              if (s.kind === "section")
                return (
                  <span
                    key={i}
                    className={`bridge-subnav-section${s.dim ? " dim" : ""}`}
                    style={s.indent ? { marginLeft: 14 } : undefined}
                  >
                    {s.label}
                  </span>
                );
              const active = activeSurface === s.page;
              return (
                <Link
                  key={i}
                  href={`/bridge/${dept}/${s.page}`}
                  prefetch
                  className={`bridge-subnav-item${active ? " active" : ""}`}
                >
                  {s.label}
                </Link>
              );
            })
          )}
        </nav>

        {/* Active surface */}
        {children}
      </main>
    </aside>
  );
}
